import{_ as n,C as o,o as r,c as l,a2 as a,E as i}from"./chunks/framework.e-meDy3u.js";const g=JSON.parse('{"title":"Q6 · 方案里哪些真需要 Agent，哪些规则脚本就够？","description":"","frontmatter":{},"headers":[],"relativePath":"q6.md","filePath":"q6.md"}'),s={name:"q6.md"};function _(h,e,p,d,c,u){const t=o("DecisionRule");return r(),l("div",null,[e[0]||(e[0]=a('<h1 id="q6-·-方案里哪些真需要-agent-哪些规则脚本就够" tabindex="-1">Q6 · 方案里哪些真需要 Agent，哪些规则脚本就够？ <a class="header-anchor" href="#q6-·-方案里哪些真需要-agent-哪些规则脚本就够" aria-label="Permalink to &quot;Q6 · 方案里哪些真需要 Agent，哪些规则脚本就够？&quot;">​</a></h1><p class="hqq-lede">知道什么时候不该用 Agent，比会用 Agent 更值钱。克制是判断力，不是保守。</p><h2 id="结论" tabindex="-1">结论 <a class="header-anchor" href="#结论" aria-label="Permalink to &quot;结论&quot;">​</a></h2><p><strong>默认脚本，Agent 是例外。</strong> 绝大多数活儿，规则和脚本就够了；Agent 只留给&quot;输入没结构、规则写不出来、必须靠语义判断&quot;的少数地方。</p><hr><h2 id="一条铁律" tabindex="-1">一条铁律 <a class="header-anchor" href="#一条铁律" aria-label="Permalink to &quot;一条铁律&quot;">​</a></h2>',6)),i(t),e[1]||(e[1]=a('<hr><h2 id="一个被否决的设想" tabindex="-1">一个被否决的设想 <a class="header-anchor" href="#一个被否决的设想" aria-label="Permalink to &quot;一个被否决的设想&quot;">​</a></h2><p>曾经设计过一套方案：把员工填报全交给 Agent，Agent 接管浏览器、录制回放操作、顺手把数据发回来；甚至做了多智能体共享会话缓存，想省掉给每个平台定制的成本。表面上先进。</p><p>但经过实际评估后否决，原因很实在：</p><ul><li>上下文会混乱，多个人的活儿硬塞进共享上下文，有概率串味。</li><li>鸡蛋全在一个篮子，一处出问题整条线全塌。企业方案最忌讳这个。</li><li>贵，而且要保证不出错的代价不成比例。</li></ul><p>最后把方案收敛成：填报这件事根本不用 Agent，员工填一张表单，程序做字段映射、一键分发、入库回测，全是普通程序员基本功，安全、便宜、快。</p><p>这段经历就是这道题的答案本身：不是不会上 Agent，是试过把它上到不该上的地方，然后自己把它拿下来了。<strong>知道 Agent 的边界，比会用 Agent 更值钱。</strong></p><hr><h2 id="诚实边界" tabindex="-1">诚实边界 <a class="header-anchor" href="#诚实边界" aria-label="Permalink to &quot;诚实边界&quot;">​</a></h2><p>Agent 那几块（聚类、生成、归因）出的都是草稿，要人审——归因草稿可能编因果，素材候选可能踩合规。方案里这些地方全带人审边界，不是 AI 说了算。</p><p>&quot;规则能不能写出来&quot;这条线实操里有灰度，不教条，一件一件看。那个共享缓存的想法保留当实验，但清楚它的定位，不往生产方案里塞。</p>',11))])}const A=n(s,[["render",_]]);export{g as __pageData,A as default};
